{"command":"@'
$rootNames = [System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase)
Get-ChildItem -Force | ForEach-Object { [void]$rootNames.Add($_.Name) }
$dirs = Get-ChildItem -Directory -Force | Where-Object { $_.Name -ne '!' -and -not $_.Name.StartsWith('.') }
$collisions = foreach ($d in $dirs) {
  Get-ChildItem -LiteralPath $d.FullName -Recurse -File -Force -ErrorAction SilentlyContinue |
    Where-Object { $rootNames.Contains($_.Name) } |
    Select-Object @{n='FromDir';e={$d.Name}}, Name, FullName
}
$collisions | Select-Object -First 200 | Format-Table -AutoSize
if ($collisions) { "TOTAL_COLLISIONS=$($collisions.Count)" } else { 'TOTAL_COLLISIONS=0' }
'@ | python -","workdir":"C:\Users\loganf\Documents\IDAHO-VAULT","timeout_ms":10000}

{"command":"@'
$dirs = Get-ChildItem -Directory -Force | Where-Object { $_.Name -ne '!' -and -not $_.Name.StartsWith('.') }
$special = $dirs | Where-Object { $_.Name -in @('_private','_templates') }
$special | Select-Object Name,FullName
foreach ($d in $special) {
  $count = (Get-ChildItem -LiteralPath $d.FullName -Recurse -File -Force -ErrorAction SilentlyContinue | Measure-Object).Count
  "$($d.Name):FILES=$count"
}
'@ | python -","workdir":"C:\Users\loganf\Documents\IDAHO-VAULT","timeout_ms":10000}
